-- ----------------------------
-- Table structure for agricultural_products
-- ----------------------------
DROP TABLE IF EXISTS `agricultural_products`;
CREATE TABLE `agricultural_products`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `product_type` enum('其他','新鲜蔬菜','新鲜水果','鲜活水产品','活的畜禽','新鲜的肉、蛋、奶') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '产品类型',
  `product_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '产品类别',
  `variety_name_pinyin` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '拼音',
  `variety_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '品种名称',
  `aliases` json NULL COMMENT '别名及常用商品名称（JSON数组格式）',
  `aliases_pinyin` json NULL COMMENT '别名及常用商品名称（JSON数组格式）',
  `alias_count` int GENERATED ALWAYS AS (json_length(`aliases`)) VIRTUAL COMMENT '别名数量' NULL,
  `is_fresh_product` tinyint(1) NULL DEFAULT 1 COMMENT '是否属于鲜活农产品',
  `is_valid` int NULL DEFAULT NULL COMMENT '有效性 1：有效 0：无效',
  `source_attachment` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '数据来源附件',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_product_identity`(`product_type` ASC, `category` ASC, `variety_name` ASC) USING BTREE,
  INDEX `idx_product_type`(`product_type` ASC) USING BTREE,
  INDEX `idx_category`(`category` ASC) USING BTREE,
  INDEX `idx_variety_name`(`variety_name` ASC) USING BTREE,
  INDEX `idx_is_fresh`(`is_fresh_product` ASC) USING BTREE,
  INDEX `idx_alias_count`(`alias_count` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 167 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '农产品品种及别名对照表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of agricultural_products
-- ----------------------------

