-- ----------------------------
-- View structure for product_alias_view
-- ----------------------------
DROP VIEW IF EXISTS `product_alias_view`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `product_alias_view` AS select `agricultural_products`.`id` AS `id`,`agricultural_products`.`product_type` AS `产品类型`,`agricultural_products`.`category` AS `类别`,`agricultural_products`.`variety_name` AS `品种名称`,`agricultural_products`.`aliases` AS `别名列表`,`agricultural_products`.`alias_count` AS `别名数量`,`agricultural_products`.`source_attachment` AS `数据来源` from `agricultural_products` order by `agricultural_products`.`product_type`,`agricultural_products`.`category`,`agricultural_products`.`variety_name`;

-- ----------------------------
-- View structure for v_vehicle_inspection_details
-- ----------------------------
DROP VIEW IF EXISTS `v_vehicle_inspection_details`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_vehicle_inspection_details` AS select `a`.`id` AS `id`,`a`.`plate_number` AS `plate_number`,`a`.`driver_phone` AS `driver_phone`,`a`.`vehicle_type` AS `vehicle_type`,`a`.`goods_type` AS `goods_type`,`a`.`goods_category` AS `goods_category`,`a`.`load_rate` AS `load_rate`,`a`.`history_record` AS `history_record`,`a`.`body_image_path` AS `body_image_path`,`a`.`transparent_image_path` AS `transparent_image_path`,`a`.`head_image_path` AS `head_image_path`,`a`.`tail_image_path` AS `tail_image_path`,`a`.`top_image_path` AS `top_image_path`,`a`.`goods_image_path` AS `goods_image_path`,`a`.`license_image_path` AS `license_image_path`,`a`.`passcode_image_path` AS `passcode_image_path`,`a`.`passcode_vehicle_id` AS `passcode_vehicle_id`,`a`.`passcode_vehicle_display_id` AS `passcode_vehicle_display_id`,`a`.`passcode_vehicle_color_name` AS `passcode_vehicle_color_name`,`a`.`passcode_en_station_id` AS `passcode_en_station_id`,`a`.`passcode_ex_station_id` AS `passcode_ex_station_id`,`a`.`passcode_en_weight` AS `passcode_en_weight`,`a`.`passcode_ex_weight` AS `passcode_ex_weight`,`a`.`passcode_media_type` AS `passcode_media_type`,`a`.`passcode_transaction_id` AS `passcode_transaction_id`,`a`.`passcode_pass_id` AS `passcode_pass_id`,`a`.`passcode_ex_time` AS `passcode_ex_time`,`a`.`passcode_trans_pay_type` AS `passcode_trans_pay_type`,`a`.`passcode_fee` AS `passcode_fee`,`a`.`passcode_pay_fee` AS `passcode_pay_fee`,`a`.`passcode_vehicle_sign` AS `passcode_vehicle_sign`,`a`.`passcode_province_count` AS `passcode_province_count`,`a`.`operator_name` AS `operator_name`,`a`.`inspection_time` AS `inspection_time`,`a`.`created_time` AS `created_time`,`a`.`updated_time` AS `updated_time`,`b`.`product_type` AS `product_type`,`b`.`category` AS `category`,`b`.`variety_name` AS `variety_name`,`c`.`type_name` AS `container_type_name`,`d`.`type_name` AS `truck_type_name` from (((`vehicle_inspections` `a` join `agricultural_products` `b` on((`a`.`goods_type` = `b`.`product_code`))) join `container_type` `c` on((`a`.`goods_category` = `c`.`type_code`))) join `truck_type` `d` on((`a`.`vehicle_type` = `d`.`type_code`)));

SET FOREIGN_KEY_CHECKS = 1;
